var pingpong, k1, kn, dur, t0, t, nOff, n;
$bm_rt = pingpong = false;
if (numKeys > 1) {
    k1 = key(1).time;
    kn = key(numKeys).time;
    dur = $bm_sub(kn, k1);
    t0 = $bm_sub(time, k1);
    t = $bm_mod($bm_sum($bm_mod(t0, dur), dur), dur);
    nOff = $bm_mod($bm_div(t0, dur), 1) == 0 ? 0.001 : 0;
    $bm_rt = n = Math.ceil($bm_sum($bm_div(t0, dur), nOff));
    if (pingpong == true && n % 2 == 0) {
        $bm_rt = valueAtTime($bm_sub(kn, t));
    } else {
        $bm_rt = valueAtTime($bm_sum(t, k1));
    }
} else {
    $bm_rt = value;
}

